dashboard.definition:
{
	"title": "Asset Manager",
	"description": "",
	"inputs": {
		"input_6e3HIOIX": {
			"dataSources": {
				"primary": "ds_P1kPf4g7"
			},
			"options": {
				"defaultValue": [
					"*"
				],
				"items": ">frame(label, value) | prepend(formattedStatics) | objects()",
				"token": "well_bore_code_filter"
			},
			"title": "Well bore code",
			"type": "input.multiselect",
			"context": {
				"formattedConfig": {
					"number": {
						"prefix": ""
					}
				},
				"formattedStatics": ">statics | formatByType(formattedConfig)",
				"statics": [
					[
						"All"
					],
					[
						"*"
					]
				],
				"label": ">primary | seriesByName(\"WELL_BORE_CODE\") | renameSeries(\"label\") | formatByType(formattedConfig)",
				"value": ">primary | seriesByName(\"WELL_BORE_CODE\") | renameSeries(\"value\") | formatByType(formattedConfig)"
			}
		},
		"input_JLT65oJi": {
			"context": {
				"formattedConfig": {
					"number": {
						"prefix": ""
					}
				},
				"formattedStatics": ">statics | formatByType(formattedConfig)",
				"statics": [
					[
						"All"
					],
					[
						"*"
					]
				],
				"label": ">primary | seriesByName(\"WELL_TYPE\") | renameSeries(\"label\") | formatByType(formattedConfig)",
				"value": ">primary | seriesByName(\"WELL_TYPE\") | renameSeries(\"value\") | formatByType(formattedConfig)"
			},
			"dataSources": {
				"primary": "ds_P1kPf4g7"
			},
			"options": {
				"defaultValue": [
					"*"
				],
				"items": ">frame(label, value) | prepend(formattedStatics) | objects()",
				"token": "well_type_filter"
			},
			"title": "Well type",
			"type": "input.multiselect"
		},
		"input_MIm9akK5": {
			"context": {
				"formattedConfig": {
					"number": {
						"prefix": ""
					}
				},
				"formattedStatics": ">statics | formatByType(formattedConfig)",
				"statics": [
					[
						"All"
					],
					[
						"*"
					]
				],
				"label": ">primary | seriesByName(\"FLOW_KIND\") | renameSeries(\"label\") | formatByType(formattedConfig)",
				"value": ">primary | seriesByName(\"FLOW_KIND\") | renameSeries(\"value\") | formatByType(formattedConfig)"
			},
			"dataSources": {
				"primary": "ds_P1kPf4g7"
			},
			"options": {
				"defaultValue": [
					"*"
				],
				"items": ">frame(label, value) | prepend(formattedStatics) | objects()",
				"token": "flow_kind_filter"
			},
			"title": "Flow kind",
			"type": "input.multiselect"
		},
		"input_global_trp": {
			"options": {
				"defaultValue": "-24h@h,now",
				"token": "global_time"
			},
			"title": "Global Time Range",
			"type": "input.timerange"
		}
	},
	"defaults": {
		"dataSources": {
			"ds.search": {
				"options": {
					"queryParameters": {
						"earliest": "$global_time.earliest$",
						"latest": "$global_time.latest$"
					}
				}
			}
		}
	},
	"visualizations": {
		"viz_GjF2K8z6": {
			"dataSources": {
				"primary": "ds_QmxOZKmb"
			},
			"eventHandlers": [],
			"options": {
				"columnFormat": {
					"#": {
						"width": 60
					}
				},
				"count": 30,
				"showRowNumbers": true
			},
			"type": "splunk.table",
			"showProgressBar": true,
			"showLastUpdated": true
		}
	},
	"dataSources": {
		"ds_P1kPf4g7": {
			"name": "lookup_table",
			"options": {
				"query": "| inputlookup append=t oilgas_assets_wells.csv "
			},
			"type": "ds.search"
		},
		"ds_QmxOZKmb": {
			"name": "chan_search_filtered",
			"options": {
				"extend": "ds_P1kPf4g7",
				"query": "search FLOW_KIND IN ($flow_kind_filter|s$)  WELL_BORE_CODE IN ($well_bore_code_filter|s$) WELL_TYPE IN ($well_type_filter|s$)"
			},
			"type": "ds.chain"
		}
	},
	"layout": {
		"globalInputs": [
			"input_global_trp",
			"input_MIm9akK5",
			"input_JLT65oJi",
			"input_6e3HIOIX"
		],
		"layoutDefinitions": {
			"layout_1": {
				"options": {
					"display": "auto",
					"height": 960,
					"width": 1440
				},
				"structure": [
					{
						"item": "viz_GjF2K8z6",
						"position": {
							"h": 720,
							"w": 1390,
							"x": 10,
							"y": 10
						},
						"type": "block"
					}
				],
				"type": "absolute"
			}
		},
		"options": {},
		"tabs": {
			"items": [
				{
					"label": "Assets table",
					"layoutId": "layout_1"
				}
			]
		}
	}
}
